// JanaShakti AI proxy — keeps API keys server-side; returns { text }.
const body = $input.first().json.body || $input.first().json;
const provider = (body.provider || 'gemini').toLowerCase();
const parts = body.parts || [];

const GEMINI_KEY = $env.JANASHAKTI_GEMINI_KEY;
const OPENAI_KEY = $env.JANASHAKTI_OPENAI_KEY;

let text = '';

if (provider === 'gpt' || provider === 'openai') {
  const content = parts.map(p => {
    if (p.text) return { type: 'text', text: p.text };
    if (p.inline_data) return { type: 'image_url', image_url: { url: 'data:' + p.inline_data.mime_type + ';base64,' + p.inline_data.data } };
    return null;
  }).filter(Boolean);

  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: { Authorization: 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
    body: { model: 'gpt-4o-mini', messages: [{ role: 'user', content }], temperature: 0.1 },
    json: true,
  });
  text = (resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content) || '';
} else {
  // Gemini chain — fall through on failure.
  const models = ['gemini-2.5-flash', 'gemini-2.5-flash-lite', 'gemini-2.0-flash'];
  for (const model of models) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent?key=' + GEMINI_KEY,
        headers: { 'Content-Type': 'application/json' },
        body: { contents: [{ parts }], generationConfig: { temperature: 0.1 } },
        json: true,
      });
      const t = resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts[0] && resp.candidates[0].content.parts[0].text;
      if (t) { text = t; break; }
    } catch (e) { /* try next model */ }
  }
}

return [{ json: { text } }];
